Thanks for the response. I believe the `stSetFilter` is the best use-case for this example. I mocked up a quick filter example utilizing underscore, in case others run into a similar issue. Thanks again and awesome work on smart table. 

```
(function() {
    'use strict';

    angular
        .module('smart-table')
        .filter('smartTableFilter', smartTableFilter);

    /** @ngInject */
    function smartTableFilter(_) {
        return function (array, expression) {
            return _.filter(array, function(object) {
                var values = _.values(object);
                return _.find(values, function(value) {
                    if(angular.isUndefined(expression.$))
                        return true;
                    if(angular.isArray(value))
                        value = value.join(', ');
                    if(angular.isString(value))
                        return value.toLowerCase().indexOf(expression.$.toLowerCase()) !== -1;
                    if(angular.isNumber(value)) {
                        var dateValue = Date.parse(value);
                        if(isNaN(dateValue))
                            return value.toString().indexOf(expression.$.toLowerCase()) !== -1;
                        else
                            return dateValue.indexOf(expression.$.toLowerCase()) !== -1;
                    }
                    return false;
                });
            });
        }
    }
    
})();
```

