	from graphene.relay.connection import PageInfo
	from graphql_relay.connection.arrayconnection import connection_from_list_slice

	import graphene
	from graphene import relay
	from graphene_sqlalchemy import SQLAlchemyConnectionField, SQLAlchemyObjectType

	class UserActivitiesConnectionField(SQLAlchemyConnectionField):
		def __init__(self):
			super().__init__(Activity)

		@classmethod
		def connection_resolver(cls, resolver, connection, model, root, args, context, info):
			"""
			Override Default method so that we can pass the root to the get_query method
			"""
			iterable = resolver(root, args, context, info)
			if iterable is None:
				iterable = cls.get_query(model, root, context, info, args)
			if isinstance(iterable, Query):
				_len = iterable.count()
			else:
				_len = len(iterable)
			return connection_from_list_slice(
				iterable,
				args,
				slice_start=0,
				list_length=_len,
				list_slice_length=_len,
				connection_type=connection,
				pageinfo_type=PageInfo,
				edge_type=connection.Edge,
			)

		# noinspection PyMethodOverriding
		@classmethod
		def get_query(cls, model: db_model.Activity, root: db_model.User, context, info, args):
			if not root:
				return []
			query.filter(model.user_id == root.id)
			return query

	class User(SQLAlchemyObjectType):
		class Meta:
			model = db_model.User
			interfaces = (relay.Node,)


